sqlReaderQuery.value:
select watermark_value 
from watermarkTable 
where tablename = '@{item().tableName}';

SELECT * FROM @{item().tableName}
WHERE @{item().waterMark_column} > '@{formatDateTime(activity('Lookup for old watermark value').output.firstRow.watermark_value, 'yyyy-MM-ddTHH:mm:ss')}' 
AND @{item().waterMark_column} <= '@{formatDateTime(activity('Lookup for new watermark value').output.firstRow.newWatermarkValue, 'yyyy-MM-ddTHH:mm:ss')}';
